import"./modulepreload-polyfill-B5Qt9EMX.js";/* empty css              */const n="http://localhost:3000/api/auth";document.getElementById("forgot-form").addEventListener("submit",async r=>{r.preventDefault();const s=new FormData(r.target).get("correo").trim(),t=document.getElementById("message");t.style.color="var(--muted, #7a8a80)",t.textContent="Enviando correo...",console.log("[FORGOT-PASSWORD] Request:",{url:`${n}/recover-password`,payload:{correo:s}});try{const e=await fetch(`${n}/recover-password`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({correo:s})});let o={};const a=await e.text();if(a&&(o=JSON.parse(a)),console.log("[FORGOT-PASSWORD] Response:",{status:e.status,body:o}),!e.ok)throw new Error(o.message||"Error al enviar");t.style.color="var(--success, #27ae60)",t.textContent=o.message||"Enlace enviado. Revise su correo.",r.target.reset()}catch(e){console.error("[FORGOT-PASSWORD] Error:",e),t.style.color="var(--error, #c0392b)",t.textContent=e.name==="TypeError"?"No se pudo conectar al servidor.":e.message}});
